// Subsets (no duplicates in input)
public List<List<Integer>> subsets(int[] nums) {
    List<List<Integer>> result = new ArrayList<>();
    backtrack(nums, 0, new ArrayList<>(), result);
    return result;
}
private void backtrack(int[] nums, int start, List<Integer> path,
                        List<List<Integer>> result) {
    result.add(new ArrayList<>(path)); // add at every node, not just leaves
    for (int i = start; i < nums.length; i++) {
        path.add(nums[i]);
        backtrack(nums, i + 1, path, result);
        path.remove(path.size() - 1); // backtrack
    }
}

// Subsets II (input may have duplicates)
public List<List<Integer>> subsetsWithDup(int[] nums) {
    Arrays.sort(nums); // sort to group duplicates
    List<List<Integer>> result = new ArrayList<>();
    backtrack2(nums, 0, new ArrayList<>(), result);
    return result;
}
private void backtrack2(int[] nums, int start, List<Integer> path,
                         List<List<Integer>> result) {
    result.add(new ArrayList<>(path));
    for (int i = start; i < nums.length; i++) {
        if (i > start && nums[i] == nums[i-1]) continue; // skip duplicates
        path.add(nums[i]);
        backtrack2(nums, i + 1, path, result);
        path.remove(path.size() - 1);
    }
}

// Bitmask approach
public List<List<Integer>> subsetsBitmask(int[] nums) {
    int n = nums.length;
    List<List<Integer>> result = new ArrayList<>();
    for (int mask = 0; mask < (1 << n); mask++) {
        List<Integer> subset = new ArrayList<>();
        for (int j = 0; j < n; j++) {
            if ((mask & (1 << j)) != 0) subset.add(nums[j]);
        }
        result.add(subset);
    }
    return result;
}

// Permutations (distinct elements)
public List<List<Integer>> permute(int[] nums) {
    List<List<Integer>> result = new ArrayList<>();
    boolean[] visited = new boolean[nums.length];
    backtrack(nums, visited, new ArrayList<>(), result);
    return result;
}
private void backtrack(int[] nums, boolean[] visited, List<Integer> path,
                        List<List<Integer>> result) {
    if (path.size() == nums.length) {
        result.add(new ArrayList<>(path));
        return;
    }
    for (int i = 0; i < nums.length; i++) {
        if (visited[i]) continue;
        visited[i] = true;
        path.add(nums[i]);
        backtrack(nums, visited, path, result);
        path.remove(path.size() - 1);
        visited[i] = false;
    }
}

// Permutations II (with duplicates)
public List<List<Integer>> permuteUnique(int[] nums) {
    Arrays.sort(nums);
    List<List<Integer>> result = new ArrayList<>();
    boolean[] visited = new boolean[nums.length];
    backtrack2(nums, visited, new ArrayList<>(), result);
    return result;
}
private void backtrack2(int[] nums, boolean[] visited, List<Integer> path,
                         List<List<Integer>> result) {
    if (path.size() == nums.length) {
        result.add(new ArrayList<>(path));
        return;
    }
    for (int i = 0; i < nums.length; i++) {
        if (visited[i]) continue;
        // Skip duplicate: same value, previous not visited
        if (i > 0 && nums[i] == nums[i-1] && !visited[i-1]) continue;
        visited[i] = true;
        path.add(nums[i]);
        backtrack2(nums, visited, path, result);
        path.remove(path.size() - 1);
        visited[i] = false;
    }
}

// Combination Sum I: reuse allowed, no duplicates in candidates
public List<List<Integer>> combinationSum(int[] candidates, int target) {
    List<List<Integer>> result = new ArrayList<>();
    Arrays.sort(candidates);
    backtrack(candidates, target, 0, new ArrayList<>(), result);
    return result;
}
private void backtrack(int[] candidates, int remaining, int start,
                        List<Integer> path, List<List<Integer>> result) {
    if (remaining == 0) { result.add(new ArrayList<>(path)); return; }
    for (int i = start; i < candidates.length; i++) {
        if (candidates[i] > remaining) break; // pruning (sorted array)
        path.add(candidates[i]);
        backtrack(candidates, remaining - candidates[i], i, path, result); // i not i+1
        path.remove(path.size() - 1);
    }
}

// Combination Sum II: each used once, candidates may have duplicates
public List<List<Integer>> combinationSum2(int[] candidates, int target) {
    Arrays.sort(candidates);
    List<List<Integer>> result = new ArrayList<>();
    backtrack2(candidates, target, 0, new ArrayList<>(), result);
    return result;
}
private void backtrack2(int[] candidates, int remaining, int start,
                         List<Integer> path, List<List<Integer>> result) {
    if (remaining == 0) { result.add(new ArrayList<>(path)); return; }
    for (int i = start; i < candidates.length; i++) {
        if (candidates[i] > remaining) break;
        if (i > start && candidates[i] == candidates[i-1]) continue; // skip duplicates
        path.add(candidates[i]);
        backtrack2(candidates, remaining - candidates[i], i + 1, path, result);
        path.remove(path.size() - 1);
    }
}

public List<List<String>> solveNQueens(int n) {
    List<List<String>> result = new ArrayList<>();
    int[] queens = new int[n]; // queens[row] = column
    Arrays.fill(queens, -1);
    Set<Integer> cols = new HashSet<>(), diag = new HashSet<>(), antiDiag = new HashSet<>();
    backtrack(n, 0, queens, cols, diag, antiDiag, result);
    return result;
}

private void backtrack(int n, int row, int[] queens,
                        Set<Integer> cols, Set<Integer> diag, Set<Integer> antiDiag,
                        List<List<String>> result) {
    if (row == n) {
        result.add(buildBoard(queens, n));
        return;
    }
    for (int col = 0; col < n; col++) {
        if (cols.contains(col) || diag.contains(row - col) || antiDiag.contains(row + col))
            continue;
        queens[row] = col;
        cols.add(col); diag.add(row - col); antiDiag.add(row + col);
        backtrack(n, row + 1, queens, cols, diag, antiDiag, result);
        queens[row] = -1;
        cols.remove(col); diag.remove(row - col); antiDiag.remove(row + col);
    }
}

private List<String> buildBoard(int[] queens, int n) {
    List<String> board = new ArrayList<>();
    for (int row = 0; row < n; row++) {
        char[] line = new char[n];
        Arrays.fill(line, '.');
        line[queens[row]] = 'Q';
        board.add(new String(line));
    }
    return board;
}

// Count solutions only
public int totalNQueens(int n) {
    int[] count = {0};
    Set<Integer> cols = new HashSet<>(), diag = new HashSet<>(), antiDiag = new HashSet<>();
    countBacktrack(n, 0, cols, diag, antiDiag, count);
    return count[0];
}
private void countBacktrack(int n, int row, Set<Integer> cols,
                              Set<Integer> diag, Set<Integer> antiDiag, int[] count) {
    if (row == n) { count[0]++; return; }
    for (int col = 0; col < n; col++) {
        if (cols.contains(col) || diag.contains(row - col) || antiDiag.contains(row + col)) continue;
        cols.add(col); diag.add(row - col); antiDiag.add(row + col);
        countBacktrack(n, row + 1, cols, diag, antiDiag, count);
        cols.remove(col); diag.remove(row - col); antiDiag.remove(row + col);
    }
}
